  1	import * as React from 'react';
  2	import NamespaceSafetyBox from '@odf/core/components/utils/safety-box';
  3	import { useSafeK8sList } from '@odf/core/hooks';
  4	import { useODFNamespaceSelector } from '@odf/core/redux';
  5	import { NooBaaBackingStoreModel } from '@odf/shared';
  6	import {
  7	  fieldRequirementsTranslations,
  8	  formSettings,
  9	} from '@odf/shared/constants';
 10	import StaticDropdown from '@odf/shared/dropdown/StaticDropdown';
 11	import { FormGroupController } from '@odf/shared/form-group-controller';
 12	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
 13	import { TextInputWithFieldRequirements } from '@odf/shared/input-with-requirements';
 14	import { SecretModel } from '@odf/shared/models';
 15	import { getName } from '@odf/shared/selectors';
 16	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 17	import { referenceForModel } from '@odf/shared/utils';
 18	import validationRegEx from '@odf/shared/utils/validation';
 19	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 20	import {
 21	  getAPIVersionForModel,
 22	  k8sCreate,
 23	  useFlag,
 24	} from '@openshift-console/dynamic-plugin-sdk';
 25	import classNames from 'classnames';
 26	import { useForm } from 'react-hook-form';
 27	import { useNavigate } from 'react-router-dom-v5-compat';
 28	import * as Yup from 'yup';
 29	import { ActionGroup, Alert, Button, Form } from '@patternfly/react-core';
 30	import {
 31	  StoreProviders,
 32	  BUCKET_LABEL_NOOBAA_MAP,
 33	  NOOBAA_TYPE_MAP,
 34	  PROVIDERS_NOOBAA_MAP,
 35	  StoreType,
 36	  providerSchema,
 37	} from '../../constants';
 38	import { ODF_MODEL_FLAG } from '../../features';
 39	import { BackingStoreKind, MCGPayload } from '../../types';
 40	import {
 41	  getExternalProviders,
 42	  getProviders,
 43	  secretPayloadCreator,
 44	} from '../../utils';
 45	import { GCPEndpointType } from '../mcg-endpoints/gcp-endpoint-type';
 46	import { PVCType } from '../mcg-endpoints/pvc-endpoint-type';
 47	import { S3EndPointType } from '../mcg-endpoints/s3-endpoint-type';
 48	import { providerDataReducer, initialState } from './reducer';
 49	import '../mcg-endpoints/noobaa-provider-endpoints.scss';
 50	
 51	const PROVIDERS = getProviders(StoreType.BS);
 52	const externalProviders = getExternalProviders(StoreType.BS);
 53	
 54	const CreateBackingStoreForm: React.FC<CreateBackingStoreFormProps> = (
 55	  props
 56	) => {
 57	  const { t } = useCustomTranslation();
 58	  const [providerDataState, providerDataDispatch] = React.useReducer(
 59	    providerDataReducer,
 60	    initialState
 61	  );
 62	
 63	  const { odfNamespace } = useODFNamespaceSelector();
 64	
 65	  const [inProgress, setProgress] = React.useState(false);
 66	  const [error, setError] = React.useState('');
 67	  const [showSecret, setShowSecret] = React.useState(true);
 68	
 69	  const isODF = useFlag(ODF_MODEL_FLAG);
 70	
 71	  const navigate = useNavigate();
 72	
 73	  const { className, isPage, appName, namespace, onCancel, onClose } = props;
 74	  const ns = namespace || odfNamespace;
 75	
 76	  const [data, loaded, loadError] = useSafeK8sList<BackingStoreKind>(
 77	    NooBaaBackingStoreModel,
 78	    ns
 79	  );
 80	
 81	  const { schema, fieldRequirements } = React.useMemo(() => {
 82	    const existingNames =
 83	      loaded && !loadError ? data?.map((dataItem) => getName(dataItem)) : [];
 84	
 85	    const fieldRequirements = [
 86	      fieldRequirementsTranslations.maxChars(t, 43),
 87	      fieldRequirementsTranslations.startAndEndName(t),
 88	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
 89	      fieldRequirementsTranslations.uniqueName(t, 'BackingStore'),
 90	    ];
 91	
 92	    const baseSchema = Yup.object({
 93	      'backingstore-name': Yup.string()
 94	        .required()
 95	        .max(43, fieldRequirements[0])
 96	        .matches(
 97	          validationRegEx.startAndEndsWithAlphanumerics,
 98	          fieldRequirements[1]
 99	        )
100	        .matches(
101	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
102	          fieldRequirements[2]
103	        )
104	        .test(
105	          'unique-name',
106	          fieldRequirements[3],
107	          (value: string) => !existingNames.includes(value)
108	        ),
109	    });
110	
111	    const schema = baseSchema.concat(providerSchema(showSecret));
112	
113	    return { schema, fieldRequirements };
114	  }, [data, loadError, loaded, showSecret, t]);
115	
116	  const resolver = useYupValidationResolver(schema);
117	
118	  const {
119	    control,
120	    handleSubmit,
121	    watch,
122	    formState: { isValid, isSubmitted },
123	  } = useForm({
124	    ...formSettings,
125	    resolver,
126	  });
127	
128	  const provider = watch('provider-name');
129	
130	  const onSubmit = (values, event) => {
131	    event.preventDefault();
132	    setProgress(true);
133	    const bsName = values['backingstore-name'];
134	    /** Create a secret if secret ==='' */
135	    let { secretName } = providerDataState;
136	    const promises = [];
137	    if (!secretName && provider !== StoreProviders.PVC) {
138	      secretName = bsName.concat('-secret');
139	      const { secretKey, accessKey, gcpJSON } = providerDataState;
140	      const secretPayload = secretPayloadCreator(
141	        provider,
142	        ns,
143	        secretName,
144	        accessKey || gcpJSON,
145	        secretKey
146	      );
147	      providerDataDispatch({ type: 'setSecretName', value: secretName });
148	      promises.push(k8sCreate({ model: SecretModel, data: secretPayload }));
149	    }
150	    /** Payload for bs */
151	    const bsPayload: MCGPayload = {
152	      apiVersion: getAPIVersionForModel(NooBaaBackingStoreModel),
153	      kind: NooBaaBackingStoreModel.kind,
154	      metadata: {
155	        namespace: ns,
156	        name: bsName,
157	      },
158	      spec: {
159	        type: NOOBAA_TYPE_MAP[provider],
160	      },
161	    };
162	    if (provider === StoreProviders.PVC) {
163	      // eslint-disable-next-line
164	      bsPayload.spec['pvPool'] = {
165	        numVolumes: providerDataState.numVolumes,
166	        storageClass: providerDataState.storageClass,
167	        resources: {
168	          requests: {
169	            storage: providerDataState.volumeSize,
170	          },
171	        },
172	      };
173	    } else if (externalProviders.includes(provider)) {
174	      bsPayload.spec = {
175	        ...bsPayload.spec,
176	        [PROVIDERS_NOOBAA_MAP[provider]]: {
177	          [BUCKET_LABEL_NOOBAA_MAP[provider]]: providerDataState.target,
178	          secret: {
179	            name: secretName,
180	            namespace: ns,
181	          },
182	        },
183	      };
184	    }
185	    if (provider === StoreProviders.S3) {
186	      // eslint-disable-next-line
187	      bsPayload.spec['s3Compatible'] = {
188	        // eslint-disable-next-line
189	        ...bsPayload.spec['s3Compatible'],
190	        endpoint: providerDataState.endpoint,
191	      };
192	    } else if (provider === StoreProviders.IBM) {
193	      bsPayload.spec.ibmCos = {
194	        ...bsPayload.spec.ibmCos,
195	        endpoint: providerDataState.endpoint,
196	      };
197	    }
198	    // Add region in the end
199	    if (provider === StoreProviders.AWS) {
200	      bsPayload.spec.awsS3 = {
201	        ...bsPayload.spec.awsS3,
202	        region: providerDataState.region,
203	      };
204	    }
205	
206	    promises.push(
207	      k8sCreate({ model: NooBaaBackingStoreModel, data: bsPayload })
208	    );
209	    return Promise.all(promises)
210	      .then((resource) => {
211	        const lastIndex = resource.length - 1;
212	        const resourcePath = `${referenceForModel(
213	          NooBaaBackingStoreModel
214	        )}/${getName(resource[lastIndex])}`;
215	        if (isPage)
216	          isODF
217	            ? navigate(`/odf/resource/${resourcePath}`)
218	            : navigate(
219	                `/k8s/ns/${ns}/clusterserviceversions/${appName}/${resourcePath}`
220	              );
221	        else onClose();
222	      })
223	      .catch((err) => {
224	        setError(err.message);
225	      })
226	      .finally(() => setProgress(false));
227	  };
228	
229	  return (
230	    <NamespaceSafetyBox>
231	      <Form
232	        className={classNames('nb-endpoints-form', className)}
233	        onSubmit={handleSubmit(onSubmit)}
234	      >
235	        <TextInputWithFieldRequirements
236	          control={control}
237	          fieldRequirements={fieldRequirements}
238	          popoverProps={{
239	            headerContent: t('Name requirements'),
240	            footerContent: `${t('Example')}: my-backingstore`,
241	          }}
242	          formGroupProps={{
243	            label: t('BackingStore Name'),
244	            fieldId: 'backingstore-name',
245	            className: 'nb-endpoints-form-entry',
246	            isRequired: true,
247	          }}
248	          textInputProps={{
249	            name: 'backingstore-name',
250	            placeholder: 'my-backingstore',
251	            'data-test': 'backingstore-name',
252	            'aria-label': t('BackingStore Name'),
253	          }}
254	        />
255	
256	        <FormGroupController
257	          name="provider-name"
258	          control={control}
259	          defaultValue={StoreProviders.AWS}
260	          formGroupProps={{
261	            label: t('Provider'),
262	            fieldId: 'provider-name',
263	            className: 'nb-endpoints-form-entry',
264	            isRequired: true,
265	          }}
266	          render={({ value, onChange, onBlur }) => (
267	            <StaticDropdown
268	              className="nb-endpoints-form-entry__dropdown"
269	              onSelect={onChange}
270	              onBlur={onBlur}
271	              dropdownItems={PROVIDERS}
272	              defaultSelection={value}
273	              data-test="backingstore-provider"
274	              isFullWidth
275	            />
276	          )}
277	        />
278	        {provider === StoreProviders.GCP && (
279	          <GCPEndpointType
280	            control={control}
281	            state={providerDataState}
282	            dispatch={providerDataDispatch}
283	            namespace={ns}
284	          />
285	        )}
286	        {(provider === StoreProviders.AWS ||
287	          provider === StoreProviders.S3 ||
288	          provider === StoreProviders.IBM ||
289	          provider === StoreProviders.AZURE) && (
290	          <S3EndPointType
291	            showSecret={showSecret}
292	            setShowSecret={setShowSecret}
293	            control={control}
294	            type={StoreType.BS}
295	            provider={provider}
296	            namespace={ns}
297	            state={providerDataState}
298	            dispatch={providerDataDispatch}
299	          />
300	        )}
301	        {provider === StoreProviders.PVC && (
302	          <PVCType state={providerDataState} dispatch={providerDataDispatch} />
303	        )}
304	        {!isValid && isSubmitted && (
305	          <Alert
306	            variant="danger"
307	            isInline
308	            title={t('Address form errors to proceed')}
309	          />
310	        )}
311	        <ButtonBar errorMessage={error} inProgress={inProgress}>
312	          <ActionGroup>
313	            <Button
314	              isDisabled={
315	                provider === StoreProviders.PVC &&
316	                providerDataState.numVolumes < 1
317	              }
318	              type="submit"
319	              data-test="backingstore-create-button"
320	              variant="primary"
321	            >
322	              {t('Create BackingStore')}
323	            </Button>
324	            <Button onClick={onCancel} variant="secondary">
325	              {t('Cancel')}
326	            </Button>
327	          </ActionGroup>
328	        </ButtonBar>
329	      </Form>
330	    </NamespaceSafetyBox>
331	  );
332	};
333	
334	export default CreateBackingStoreForm;
335	
336	type CreateBackingStoreFormProps = {
337	  isPage?: boolean;
338	  namespace?: string;
339	  className?: string;
340	  appName?: string;
341	  onCancel: any;
342	  onClose?: any;
343	};

